/**
 * Applies db/schema.sql to your Supabase Postgres database.
 *
 * Requires SUPABASE_DB_PASSWORD in .env.local (from Supabase → Project Settings → Database).
 * Optional: SUPABASE_DB_HOST (defaults to aws-0-us-east-1.pooler.supabase.com)
 *
 * Usage: node db/apply-schema.mjs
 */

import pg from "pg";
import { readFileSync } from "fs";
import { resolve, dirname } from "path";
import { fileURLToPath } from "url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const envPath = resolve(__dirname, "../.env.local");
const env = readFileSync(envPath, "utf8");
const get = (key) => env.match(new RegExp(`^${key}=(.+)$`, "m"))?.[1]?.trim();

const url = get("NEXT_PUBLIC_SUPABASE_URL");
const password = get("SUPABASE_DB_PASSWORD");
const host =
  get("SUPABASE_DB_HOST") ?? "aws-0-us-east-1.pooler.supabase.com";

if (!url || !password) {
  console.error(
    "Add SUPABASE_DB_PASSWORD to .env.local (Supabase → Project Settings → Database → Database password)",
  );
  process.exit(1);
}

const projectRef = url.replace("https://", "").replace(".supabase.co", "");
const connectionString = `REDACTED`;

const sql = readFileSync(resolve(__dirname, "schema.sql"), "utf8");
const client = new pg.Client({ connectionString, ssl: { rejectUnauthorized: false } });

try {
  await client.connect();
  console.log("Connected. Applying schema...");
  await client.query(sql);
  console.log("Schema applied successfully.");
} catch (error) {
  console.error("Failed to apply schema:", error.message);
  process.exit(1);
} finally {
  await client.end();
}

import { createClient } from "@supabase/supabase-js";

export function createAdminClient() {
  return createClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.SUPABASE_SERVICE_ROLE_KEY!,
    {
      auth: {
        autoRefreshToken: false,
        persistSession: false,
      },
    },
  );
}

import { NextResponse } from "next/server";
import { createClient } from "@/lib/supabase/server";
import { createAdminClient } from "@/lib/supabase/admin";

const HANDLE_PATTERN = /^[a-z0-9_]{3,30}$/;

async function getAuthenticatedUser(request: Request) {
  const supabase = await createClient();
  const authHeader = request.headers.get("Authorization");

  if (authHeader?.startsWith("Bearer ")) {
    const token = authHeader.slice(7);
    const {
      data: { user },
    } = await supabase.auth.getUser(token);
    if (user) {
      return user;
    }
  }

  const {
    data: { user },
  } = await supabase.auth.getUser();

  return user;
}

export async function POST(request: Request) {
  const user = await getAuthenticatedUser(request);

  if (!user) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  let body: { handle?: string };

  try {
    body = await request.json();
  } catch {
    return NextResponse.json({ error: "Invalid request body" }, { status: 400 });
  }

  const handle = body.handle?.trim().toLowerCase();

  if (!handle || !HANDLE_PATTERN.test(handle)) {
    return NextResponse.json(
      { error: "Handle must be 3–30 characters: lowercase letters, numbers, and underscores only" },
      { status: 400 },
    );
  }

  const admin = createAdminClient();
  const { error } = await admin.from("profiles").insert({
    id: user.id,
    handle,
  });

  if (error) {
    if (error.code === "23505") {
      return NextResponse.json({ error: "handle already taken" }, { status: 409 });
    }

    console.error("create-profile insert error:", error);
    return NextResponse.json({ error: "Failed to create profile" }, { status: 500 });
  }

  return NextResponse.json({ handle }, { status: 201 });
}

import { NextResponse } from "next/server";
import { resend } from "@/lib/resend/client";
import { welcomeEmailHtml } from "@/lib/resend/templates/welcome";

export async function POST(request: Request) {
  let body: { email?: string; handle?: string };

  try {
    body = await request.json();
  } catch {
    return NextResponse.json({ error: "Invalid request body" }, { status: 400 });
  }

  const email = body.email?.trim();
  const handle = body.handle?.trim().toLowerCase();

  if (!email || !handle) {
    return NextResponse.json(
      { error: "email and handle are required" },
      { status: 400 },
    );
  }

  try {
    const { error } = await resend.emails.send({
      from: "Bookmarks <onboarding@resend.dev>",
      to: email,
      subject: `Welcome to Bookmarks, @${handle}`,
      html: welcomeEmailHtml(handle),
    });

    if (error) {
      console.error("welcome email error:", error);
      return NextResponse.json({ error: "Failed to send email" }, { status: 500 });
    }

    return NextResponse.json({ success: true }, { status: 200 });
  } catch (error) {
    console.error("welcome email error:", error);
    return NextResponse.json({ error: "Failed to send email" }, { status: 500 });
  }
}

"use client";

import Link from "next/link";
import { useState, type FormEvent } from "react";
import { createClient } from "@/lib/supabase/client";

const HANDLE_PATTERN = /^[a-z0-9_]{3,30}$/;

export default function SignupForm() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [handle, setHandle] = useState("");
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  async function handleSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setError(null);

    if (password.length < 8) {
      setError("Password must be at least 8 characters");
      return;
    }

    const normalizedHandle = handle.trim().toLowerCase();

    if (!HANDLE_PATTERN.test(normalizedHandle)) {
      setError(
        "Handle must be 3–30 characters: lowercase letters, numbers, and underscores only",
      );
      return;
    }

    setLoading(true);

    try {
      const supabase = createClient();
      const { data, error: signUpError } = await supabase.auth.signUp({
        email: email.trim(),
        password,
      });

      if (signUpError) {
        const message = signUpError.message.toLowerCase();

        if (
          message.includes("already registered") ||
          message.includes("already exists") ||
          signUpError.code === "user_already_exists"
        ) {
          setError("Email already in use");
          return;
        }

        setError(signUpError.message);
        return;
      }

      if (!data.user) {
        setError("Unable to create account. Please try again.");
        return;
      }

      const headers: HeadersInit = {
        "Content-Type": "application/json",
      };

      if (data.session?.access_token) {
        headers.Authorization = `Bearer ${data.session.access_token}`;
      }

      const profileResponse = await fetch("/api/auth/create-profile", {
        method: "POST",
        headers,
        credentials: "include",
        body: JSON.stringify({ handle: normalizedHandle }),
      });

      if (!profileResponse.ok) {
        const profileData = await profileResponse.json().catch(() => ({}));

        if (profileResponse.status === 409) {
          setError("Handle already taken");
          return;
        }

        if (profileResponse.status === 401) {
          setError("Account created. Please check your email to confirm, then set your handle in settings.");
          window.location.href = "/confirm";
          return;
        }

        setError(profileData.error ?? "Failed to create profile");
        return;
      }

      await fetch("/api/email/welcome", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          email: email.trim(),
          handle: normalizedHandle,
        }),
      });

      window.location.href = "/confirm";
    } catch {
      setError("Something went wrong. Please try again.");
    } finally {
      setLoading(false);
    }
  }

  return (
    <form onSubmit={handleSubmit} className="flex w-full flex-col gap-4">
      <div>
        <label htmlFor="email" className="mb-1 block text-sm font-medium">
          Email
        </label>
        <input
          id="email"
          type="email"
          required
          autoComplete="email"
          value={email}
          onChange={(event) => setEmail(event.target.value)}
          className="w-full rounded-md border border-gray-300 px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
        />
      </div>

      <div>
        <label htmlFor="password" className="mb-1 block text-sm font-medium">
          Password
        </label>
        <input
          id="password"
          type="password"
          required
          minLength={8}
          autoComplete="new-password"
          value={password}
          onChange={(event) => setPassword(event.target.value)}
          className="w-full rounded-md border border-gray-300 px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
        />
        {password.length > 0 && password.length < 8 && (
          <p className="mt-1 text-sm text-red-600">Password must be at least 8 characters</p>
        )}
      </div>

      <div>
        <label htmlFor="handle" className="mb-1 block text-sm font-medium">
          Handle
        </label>
        <input
          id="handle"
          type="text"
          required
          pattern="[a-z0-9_]{3,30}"
          autoComplete="username"
          value={handle}
          onChange={(event) => setHandle(event.target.value.toLowerCase())}
          className="w-full rounded-md border border-gray-300 px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
        />
        <p className="mt-1 text-sm text-gray-500">
          lowercase letters, numbers, and underscores only
        </p>
      </div>

      {error && <p className="text-sm text-red-600">{error}</p>}

      <button
        type="submit"
        disabled={loading}
