import { NextResponse } from "next/server";
import { createAdminClient } from "@/lib/supabase/admin";
import { resend } from "@/lib/resend/client";
import { welcomeEmailHtml } from "@/lib/resend/templates/welcome";

const HANDLE_PATTERN = /^[a-z0-9_]{3,30}$/;

function getAppUrl() {
  return process.env.NEXT_PUBLIC_APP_URL ?? "http://localhost:3000";
}

async function buildConfirmationUrl(email: string, password: string) {
  const admin = createAdminClient();
  const appUrl = getAppUrl();
  const { data, error } = await admin.auth.admin.generateLink({
    type: "signup",
    email,
    password,
    options: {
      redirectTo: `${appUrl}/api/auth/confirm`,
    },
  });

  if (error) {
    console.error("confirmation link error:", error);
    return undefined;
  }

  const hashedToken = data.properties?.hashed_token;
  const verificationType = data.properties?.verification_type ?? "signup";

  if (!hashedToken) {
    return data.properties?.action_link;
  }

  const params = new URLSearchParams({
    token_hash: hashedToken,
    type: verificationType,
  });

  return `${appUrl}/api/auth/confirm?${params.toString()}`;
}

export async function POST(request: Request) {
  let body: { email?: string; password?: string; handle?: string };

  try {
    body = await request.json();
  } catch {
    return NextResponse.json({ error: "Invalid request body" }, { status: 400 });
  }

  const email = body.email?.trim();
  const password = body.password;
  const handle = body.handle?.trim().toLowerCase();

  if (!email || !password || !handle) {
    return NextResponse.json(
      { error: "email, password, and handle are required" },
      { status: 400 },
    );
  }

  if (password.length < 8) {
    return NextResponse.json(
      { error: "Password must be at least 8 characters" },
      { status: 400 },
    );
  }

  if (!HANDLE_PATTERN.test(handle)) {
    return NextResponse.json(
      {
        error:
          "Handle must be 3–30 characters: lowercase letters, numbers, and underscores only",
      },
      { status: 400 },
    );
  }

  const admin = createAdminClient();

  const { data: existingHandle } = await admin
    .from("profiles")
    .select("id")
    .eq("handle", handle)
    .maybeSingle();

  if (existingHandle) {
    return NextResponse.json({ error: "handle already taken" }, { status: 409 });
  }

  const { data: createdUser, error: createError } =
    await admin.auth.admin.createUser({
      email,
      password,
      email_confirm: false,
      user_metadata: { handle },
    });

  if (createError) {
    const message = createError.message.toLowerCase();

    if (
      message.includes("already registered") ||
      message.includes("already exists") ||
      message.includes("duplicate")
    ) {
      return NextResponse.json({ error: "Email already in use" }, { status: 409 });
    }

    if (message.includes("rate limit")) {
      return NextResponse.json(
        {
          error:
            "Too many signup attempts. Please wait a few minutes before trying again.",
        },
        { status: 429 },
      );
    }

    console.error("signup createUser error:", createError);
    return NextResponse.json({ error: "Failed to create account" }, { status: 500 });
  }

  const userId = createdUser.user?.id;

  if (!userId) {
    return NextResponse.json({ error: "Failed to create account" }, { status: 500 });
  }

  const { error: profileError } = await admin.from("profiles").insert({
    id: userId,
    handle,
  });

  if (profileError) {
    await admin.auth.admin.deleteUser(userId);

    if (profileError.code === "23505") {
      return NextResponse.json({ error: "handle already taken" }, { status: 409 });
    }

    console.error("signup profile insert error:", profileError);
    return NextResponse.json({ error: "Failed to create profile" }, { status: 500 });
  }

  const confirmUrl = await buildConfirmationUrl(email, password);

  const { error: emailError } = await resend.emails.send({
    from: "Bookmarks <onboarding@resend.dev>",
    to: email,
    subject: `Welcome to Bookmarks, @${handle}`,
    html: welcomeEmailHtml(handle, confirmUrl),
  });

  if (emailError) {
    console.error("signup welcome email error:", emailError);

    if (emailError.message?.toLowerCase().includes("rate limit")) {
      return NextResponse.json(
        {
          error:
            "Account created but email could not be sent. Please wait a few minutes and contact support.",
        },
        { status: 429 },
      );
    }
    // Account exists — signup succeeded even if welcome email fails (PRD: non-fatal)
  }

  return NextResponse.json({ success: true }, { status: 201 });
}

"use client";

import Link from "next/link";
import { useState, type FormEvent } from "react";

const HANDLE_PATTERN = /^[a-z0-9_]{3,30}$/;

export default function SignupForm() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [handle, setHandle] = useState("");
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  async function handleSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setError(null);

    if (password.length < 8) {
      setError("Password must be at least 8 characters");
      return;
    }

    const normalizedHandle = handle.trim().toLowerCase();

    if (!HANDLE_PATTERN.test(normalizedHandle)) {
      setError(
        "Handle must be 3–30 characters: lowercase letters, numbers, and underscores only",
      );
      return;
    }

    setLoading(true);

    try {
      const response = await fetch("/api/auth/signup", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          email: email.trim(),
          password,
          handle: normalizedHandle,
        }),
      });

      const data = await response.json().catch(() => ({}));

      if (!response.ok) {
        if (response.status === 409 && data.error === "Email already in use") {
          setError("Email already in use");
          return;
        }

        if (response.status === 409 && data.error === "handle already taken") {
          setError("Handle already taken");
          return;
        }

        if (response.status === 429) {
          setError(
            data.error ??
              "Too many signup attempts. Please wait a few minutes and try again.",
          );
          return;
        }

        setError(data.error ?? "Something went wrong. Please try again.");
        return;
      }

      window.location.href = "/confirm";
    } catch {
      setError("Something went wrong. Please try again.");
    } finally {
      setLoading(false);
    }
  }

  return (
    <form onSubmit={handleSubmit} className="flex w-full flex-col gap-4 text-gray-900">
      <div>
        <label htmlFor="email" className="mb-1 block text-sm font-medium text-gray-900">
          Email
        </label>
        <input
          id="email"
          type="email"
          required
          autoComplete="email"
          value={email}
          onChange={(event) => setEmail(event.target.value)}
          className="w-full rounded-md border border-gray-300 bg-white px-3 py-2 text-gray-900 placeholder:text-gray-400 focus:outline-none focus:ring-2 focus:ring-blue-500"
        />
      </div>

      <div>
        <label htmlFor="password" className="mb-1 block text-sm font-medium text-gray-900">
          Password
        </label>
        <input
          id="password"
          type="password"
          required
          minLength={8}
          autoComplete="new-password"
          value={password}
          onChange={(event) => setPassword(event.target.value)}
          className="w-full rounded-md border border-gray-300 bg-white px-3 py-2 text-gray-900 placeholder:text-gray-400 focus:outline-none focus:ring-2 focus:ring-blue-500"
        />
        {password.length > 0 && password.length < 8 && (
          <p className="mt-1 text-sm text-red-600">Password must be at least 8 characters</p>
        )}
      </div>

      <div>
        <label htmlFor="handle" className="mb-1 block text-sm font-medium text-gray-900">
          Handle
        </label>
        <input
          id="handle"
          type="text"
          required
          pattern="[a-z0-9_]{3,30}"
          autoComplete="username"
          value={handle}
          onChange={(event) => setHandle(event.target.value.toLowerCase())}
          className="w-full rounded-md border border-gray-300 bg-white px-3 py-2 text-gray-900 placeholder:text-gray-400 focus:outline-none focus:ring-2 focus:ring-blue-500"
        />
        <p className="mt-1 text-sm text-gray-500">
          lowercase letters, numbers, and underscores only
        </p>
      </div>

      {error && <p className="text-sm text-red-600">{error}</p>}

      <button
        type="submit"
        disabled={loading}
        className="rounded-md bg-blue-600 px-4 py-2 font-medium text-white hover:bg-blue-700 disabled:cursor-not-allowed disabled:opacity-60"
      >
        {loading ? "Creating account..." : "Sign up"}
      </button>

      <p className="text-center text-sm text-gray-600">
        Already have an account?{" "}
        <Link href="/login" className="font-medium text-blue-600 hover:underline">
          Log in
        </Link>
      </p>
    </form>
  );
}

