import { createClient } from "@supabase/supabase-js";
import { resend } from "@/lib/resend/client";
import { welcomeEmailHtml } from "@/lib/resend/templates/welcome";
import { buildConfirmationUrl } from "@/lib/auth/users";

function getAppUrl() {
  return process.env.NEXT_PUBLIC_APP_URL ?? "http://localhost:3000";
}

function getResendFromAddress() {
  return (
    process.env.RESEND_FROM_EMAIL ?? "Bookmarks <onboarding@resend.dev>"
  );
}

/** True when a custom domain is configured — Resend can send to any recipient. */
export function canUseResendForAnyRecipient() {
  return Boolean(process.env.RESEND_FROM_EMAIL);
}

/** Sends confirmation via Supabase Auth — works for any email address. */
export async function sendSupabaseConfirmationEmail(email: string) {
  const supabase = createClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
  );

  const { error } = await supabase.auth.resend({
    type: "signup",
    email,
    options: {
      emailRedirectTo: `${getAppUrl()}/api/auth/confirm`,
    },
  });

  return { error };
}

/** Sends branded welcome + confirm email via Resend (requires verified domain). */
export async function sendWelcomeEmailViaResend(
  email: string,
  handle: string,
  confirmUrl?: string,
) {
  return resend.emails.send({
    from: getResendFromAddress(),
    to: email,
    subject: `Welcome to Bookmarks, @${handle}`,
    html: welcomeEmailHtml(handle, confirmUrl),
  });
}

/**
 * Sends signup confirmation to any user.
 * - With RESEND_FROM_EMAIL set: custom HTML via Resend (production).
 * - Otherwise: Supabase Auth email (works for all recipients on free tier).
 */
export async function sendSignupEmail({
  email,
  handle,
  password,
}: {
  email: string;
  handle: string;
  password?: string;
}) {
  if (canUseResendForAnyRecipient() && password) {
    const confirmUrl = await buildConfirmationUrl(email, password);
    const { error } = await sendWelcomeEmailViaResend(email, handle, confirmUrl);

    if (!error) {
      return { provider: "resend" as const, error: null };
    }

    console.warn("Resend failed, falling back to Supabase email:", error.message);
  }

  const { error } = await sendSupabaseConfirmationEmail(email);
  return { provider: "supabase" as const, error };
}

